module ram64bytes(
    input clk,
    input [5:0] a,
    input [7:0] din,
    output [7:0] dout,
    input we
    );
	 reg [7:0] data_store[0:63];
	 assign dout = data_store[a];	
	 integer i;
	 initial begin
		for (i=0;i<=63;i=i+1)
			data_store[i] = i/8;
	 end
	 always @(posedge clk) begin
		if (we)
			data_store[a] <= din;
	 end
endmodule
